// T605 TenantProvisioningOrchestrator — atomic tenant bootstrap
async provision(): Promise<DataProcessResult<void>> {
  const tenantId = this.tenantContext.getTenantId(); // ALS only

  // ORDER 1: SETNX idempotency guard
  const locked = await this.provisionLock.acquire(tenantId); // F1521
  if (!locked) {
    await this.queue.enqueue('TenantProvisioningFailed', { tenantId, failureCode: 'PROVISION_LOCK_HELD' });
    return DataProcessResult.failure('PROVISION_LOCK_HELD', 'Concurrent provision in progress');
  }

  try {
    // ORDER 2: synchronous bulkSeed — sequential, never Promise.all scatter
    const defaults = await this.freedom.getConfig('tenant_default_quota_api_calls'); // F1522
    await this.seedService.seedDefaults(tenantId, defaults); // F1520 — sync, awaited

    // ORDER 3: storeDocument BEFORE enqueue (DNA-8)
    await this.registry.storeDocument('xiigen-tenants', { tenantId, status: 'ACTIVE' }); // F1519

    // ORDER 4: enqueue AFTER store
    await this.queue.enqueue('TenantProvisioned', { tenantId, freedomSeedCount: 3, status: 'ACTIVE' });
    return DataProcessResult.success();
  } catch (err) {
    await this.queue.enqueue('TenantProvisioningFailed', { tenantId, failureCode: 'PROVISION_ERROR' });
    return DataProcessResult.failure('PROVISION_ERROR', err.message);
  } finally {
    await this.provisionLock.release(tenantId); // always release
  }
}
